path foo = moo(1);
real t;

for (t = 1; t <= 359; t = t + 0.1) {
  foo = foo--moo(t);
}

draw(foo,red);

draw((-4,0)--(4,0));
draw((0,-4)--(0,4));

limits((-4,-4),(4,4),Crop);

label("$r = \frac{1}{1 - \cos \theta}$", (6.5,1.5), red);
